"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const steps=[["Plan","Scope is approved"],["Build","Interfaces are in review"],["Ship","Release checklist awaits"]];
export default function MilestoneLensNavigator(){const [active,setActive]=useState(1);const reduced=useReducedMotion();return <section className="w-full max-w-md rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">milestone lens</p><div role="tablist" aria-label="Delivery milestones" className="relative mt-4 grid grid-cols-3 rounded-2xl bg-[#f4f5f6] p-1">{steps.map(([name],index)=><button key={name} role="tab" aria-selected={active===index} onClick={()=>setActive(index)} onKeyDown={e=>{if(e.key==="ArrowRight")setActive((active+1)%3);if(e.key==="ArrowLeft")setActive((active+2)%3)}} className="relative z-10 min-h-11 rounded-xl text-sm font-black outline-offset-3 focus-visible:outline focus-visible:outline-3 focus-visible:outline-[#111]">{name}</button>)}<motion.i aria-hidden animate={{x:`${active*100}%`}} transition={reduced?{duration:0}:{type:"spring",stiffness:310,damping:25}} className="absolute inset-y-1 left-1 w-[calc(33.333%-4px)] rounded-xl border-2 border-[#111] bg-white"/></div><div role="tabpanel" className="mt-4 rounded-2xl bg-[#eefaff] p-4 text-sm text-[#4a4a4f]"><b className="text-[#111]">{steps[active][0]}</b> — {steps[active][1]}</div></section>}
